SELECT id, order_no as orderNo, user_id as userId, status, total_amount as totalAmount,
       DATE_FORMAT(created_at, '%Y-%m-%d %H:%i:%s') as createdAt
FROM orders WHERE order_no = #{orderNo}

SELECT id, order_no as orderNo, user_id as userId, status, total_amount as totalAmount,
       DATE_FORMAT(created_at, '%Y-%m-%d %H:%i:%s') as createdAt
FROM orders
WHERE user_id = #{userId}

    AND total_amount >= #{minAmount}


    AND total_amount <= #{maxAmount}

ORDER BY total_amount DESC

SELECT id, order_no as orderNo, user_id as userId, status, total_amount as totalAmount,
       DATE_FORMAT(created_at, '%Y-%m-%d %H:%i:%s') as createdAt
FROM orders
WHERE user_id = #{userId}

    AND created_at >= #{startDate}


    AND created_at <= #{endDate}

ORDER BY created_at DESC

SELECT id, order_no as orderNo, user_id as userId, status, total_amount as totalAmount,
       DATE_FORMAT(created_at, '%Y-%m-%d %H:%i:%s') as createdAt
FROM orders
WHERE user_id = #{userId}

    AND status = #{status}


    AND total_amount >= #{minAmount}


    AND total_amount <= #{maxAmount}


    AND created_at >= #{startDate}


    AND created_at <= #{endDate}

ORDER BY created_at DESC

SELECT COUNT(*) FROM orders WHERE user_id = #{userId}

    AND total_amount >= #{minAmount}


    AND total_amount <= #{maxAmount}

SELECT COALESCE(SUM(total_amount), 0) FROM orders WHERE user_id = #{userId}

    AND total_amount >= #{minAmount}


    AND total_amount <= #{maxAmount}
